    ('BUS-K 303', 'TECHNOLOGY AND BUSINESS ANALYSIS', '6425', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HH 1049', 'Joseph Baird', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'An introduction to the ways that technology enables and empowers business decision making. In this introductory analytics course you will learn how companies apply technology tools to prepare, analyze, model and display the information used to manage their business. You will apply these same techniques using spreadsheet modeling and other tools.', ARRAY['Class uses IU eTexts'], NULL),
