    ('BUS-K 303', 'TECHNOLOGY AND BUSINESS ANALYSIS', '35676', 'Closed', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'HH 1049', 'Joseph Baird', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'An introduction to the ways that technology enables and empowers business decision making. In this introductory analytics course you will learn how companies apply technology tools to prepare, analyze, model and display the information used to manage their business. You will apply these same techniques using spreadsheet modeling and other tools.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-K 304', 'TECHNOLOGY AND BUSINESS ANALYSIS - HONORS', '6468', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'CG 3075', 'Sarah Fairchild Sherry', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course provides an introduction to the decision making process, including both the relevant thought processes and the analytical decision-making tools used by companies to solve a variety of problems.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-K 304', 'TECHNOLOGY AND BUSINESS ANALYSIS - HONORS', '6470', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HH 1049', 'Sarah Fairchild Sherry', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course provides an introduction to the decision making process, including both the relevant thought processes and the analytical decision-making tools used by companies to solve a variety of problems.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-K 304', 'TECHNOLOGY AND BUSINESS ANALYSIS - HONORS', '11545', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'CG 3075', 'Sarah Fairchild Sherry', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course provides an introduction to the decision making process, including both the relevant thought processes and the analytical decision-making tools used by companies to solve a variety of problems.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-K 327', 'MODELING BUSINESS DATA', '6730', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HH 4057', 'Paul Serex', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course provides immersion into business skills including critical thinking, problem solving, process development and modeling, and analytical tools employed to convert raw data into information for decision-making. It emphasizes fundamental data analytics principles, taking a layered approach: 1) data retrieval; 2) data analysis; and 3) modeling decision-making processes.', ARRAY[]::TEXT[], NULL),
    ('BUS-K 327', 'MODELING BUSINESS DATA', '7080', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'HH 4057', 'Paul Serex', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course provides immersion into business skills including critical thinking, problem solving, process development and modeling, and analytical tools employed to convert raw data into information for decision-making. It emphasizes fundamental data analytics principles, taking a layered approach: 1) data retrieval; 2) data analysis; and 3) modeling decision-making processes.', ARRAY[]::TEXT[], NULL),
    ('BUS-K 327', 'MODELING BUSINESS DATA', '8547', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HH 4057', 'Paul Serex', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course provides immersion into business skills including critical thinking, problem solving, process development and modeling, and analytical tools employed to convert raw data into information for decision-making. It emphasizes fundamental data analytics principles, taking a layered approach: 1) data retrieval; 2) data analysis; and 3) modeling decision-making processes.', ARRAY[]::TEXT[], NULL),
    ('BUS-K 327', 'MODELING BUSINESS DATA', '14785', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HH 4057', 'Paul Serex', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course provides immersion into business skills including critical thinking, problem solving, process development and modeling, and analytical tools employed to convert raw data into information for decision-making. It emphasizes fundamental data analytics principles, taking a layered approach: 1) data retrieval; 2) data analysis; and 3) modeling decision-making processes.', ARRAY[]::TEXT[], NULL),
    ('BUS-K 353', 'BUSINESS ANALYTICS & MODELING', '7113', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'HH 4059', 'Rain Kan', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on layered process of transforming data into insights which includes descriptive analytics to characterize data, predictive analytics that centers on the use of machine learning algorithms to evaluate the likelihood of future outcomes and prescriptive analytics to identify optimal strategies to achieve the performance goals.', ARRAY[]::TEXT[], NULL),
    ('BUS-K 353', 'BUSINESS ANALYTICS & MODELING', '7115', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 4059', 'Eunae Yoo', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on layered process of transforming data into insights which includes descriptive analytics to characterize data, predictive analytics that centers on the use of machine learning algorithms to evaluate the likelihood of future outcomes and prescriptive analytics to identify optimal strategies to achieve the performance goals.', ARRAY[]::TEXT[], NULL),
