    ('BUS-L 304', 'CRITICAL THINKING, DECISION-MAKING & ADVOCACY', '9646', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 3059', 'Stephanie Moore', 0, NULL, 'Lecture', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course will improve students'' ability to understand and evaluate their own and others'' reasoning, which will develop their capacity to construct, advocate, and defend strong arguments in the business context.', ARRAY[]::TEXT[], NULL),
    ('BUS-L 304', 'CRITICAL THINKING, DECISION-MAKING & ADVOCACY', '10447', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 3059', 'Stephanie Moore', 0, NULL, 'Lecture', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course will improve students'' ability to understand and evaluate their own and others'' reasoning, which will develop their capacity to construct, advocate, and defend strong arguments in the business context.', ARRAY[]::TEXT[], NULL),
    ('BUS-L 305', 'BUSINESS PLANNING AND CORPORATE LAW', '10483', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'HH 3057', 'Kent Altom', 0, NULL, 'Lecture', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course examines the law governing business organizations--partnerships, corporations, limited liability companies, and others--and the social policy underlying the law. The primary focus is on corporations, including such topics as fundamental corporate transactions and the role, rights, powers and duties of the various corporate actors.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-L 305', 'BUSINESS PLANNING AND CORPORATE LAW', '32548', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'HH 3059', 'Kent Altom', 0, NULL, 'Lecture', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course examines the law governing business organizations--partnerships, corporations, limited liability companies, and others--and the social policy underlying the law. The primary focus is on corporations, including such topics as fundamental corporate transactions and the role, rights, powers and duties of the various corporate actors.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-L 318', 'BUSINESS & POVERTY ALLEVIATION', '10323', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 4030', 'Kelly Eskew', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Addresses potential for business to create poverty solutions by accessing the market of the world''s poorest five billion (i.e., developing products and services that are high-volume, low-margin profitable, and engage the poor as consumers and producers) and investigates causes of poverty, including influence of corporations in perpetuating root causes.', ARRAY[]::TEXT[], NULL),
    ('BUS-L 319', 'CLIMATE CHANGE LAW & POLICY', '11364', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 4030', 'Kelly Eskew', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'The course will focus on the legal framework governing energy production and consumption in the United States, business impacts (and opportunities) flowing from the environmental issues associated with various energy sectors, and policy approaches for balancing energy needs with environment protection.', ARRAY[]::TEXT[], NULL),
    ('BUS-L 328', 'SPORTS INDUSTRY WORKSHOP I', '12677', 'Closed', 'F Friday 11:35 AM–4:05 PM', 'HH 1043', 'Doug Eibling', 0, NULL, 'Practicum', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Course introduces students to business issues & trends affecting the U.S. sports industry (ii) helps students understand how to pursue, obtain, & develop a career in this competitive field. Guest speakers & class projects will enhance students'' understanding; i.e., arena management, licensing, media rights, sponsorships, talent representation, ticket sales.', ARRAY[]::TEXT[], NULL),
    ('BUS-L 355', 'TOPICS IN BUSINESS LAW & ETHICS', '14663', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'CG 2077', 'Angie Raymond', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Variable topic, variable credit course in Business Law & Ethics.', ARRAY[]::TEXT[], NULL),
    ('BUS-L 360', 'TOPICS IN BUSINESS ETHICS', '9671', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 3059', 'Shawna Eikenberry', 0, NULL, 'Discussion', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course provides an in-depth exploration of a particular dimension or issue in business ethics. Focus of the course will vary from semester to semester.', ARRAY[]::TEXT[], NULL),
    ('BUS-L 375', 'INTRODUCTION TO BUSINESS ETHICS', '5591', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'HH 1034', 'Stephanie Moore', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course will enhance students'' ability to perceive ethical concerns inherent in business decisions and make reasoned judgments about them using basic tools of ethical reasoning. Students will have the opportunity to practice and reflect upon responses to ethical dilemmas within business relationships and organization.', ARRAY['Class uses IU eTexts'], NULL),
