    ('BUS-L 408', 'REAL ESTATE LAW', '12492', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'HH 3059', 'Lara Grow', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Legal aspects of ownership, transfer, leasing, and financing of real property. Major legal issues of land-use control.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-L 413', 'APPLIED DISPUTE RESOLUTION', '11112', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 3059', 'Stephanie Moore', 0, NULL, 'Discussion', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This Law, Ethics & Decision Making capstone course builds upon the argumentation and persuasion skills and the legal and ethical frameworks gained in previous coursework. Through a series of applied exercises, it develops and hones students'' skills in legal research, negotiation, written and oral advocacy, and dispute resolution.', ARRAY[]::TEXT[], NULL),
    ('BUS-L 521', 'CRITICAL THOUGHT AND PRACTICAL WISDOM', '5875', 'Class Status', 'TuTh Tuesday, Thursday 2:30 PM–3:45 PM', 'CG 1014', 'Todd Haugh', 5, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course is designed to improve your ability to evaluate information and arguments, make rational decisions, and advocate and defend your judgments. You will also learn to cultivate wisdom by integrating good reasoning practices with personal experience, empathy, and ethical analysis.', ARRAY[]::TEXT[], NULL),
    ('BUS-L 521', 'CRITICAL THOUGHT AND PRACTICAL WISDOM', '9987', 'Class Status', 'TuTh Tuesday, Thursday 11:00 AM–12:15 PM', 'CG 2077', 'Todd Haugh', 5, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course is designed to improve your ability to evaluate information and arguments, make rational decisions, and advocate and defend your judgments. You will also learn to cultivate wisdom by integrating good reasoning practices with personal experience, empathy, and ethical analysis.', ARRAY[]::TEXT[], NULL),
    ('BUS-L 521', 'CRITICAL THOUGHT AND PRACTICAL WISDOM', '32451', 'Class Status', 'TuTh Tuesday, Thursday 9:30 AM–10:45 AM', 'CG 2077', 'Todd Haugh', 4, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course is designed to improve your ability to evaluate information and arguments, make rational decisions, and advocate and defend your judgments. You will also learn to cultivate wisdom by integrating good reasoning practices with personal experience, empathy, and ethical analysis.', ARRAY[]::TEXT[], NULL),
    ('BUS-L 540', 'COMMERCIAL FINANCE LAW: CREDITORS'' RIGHT', '14367', 'Class Status', 'TuTh Tuesday, Thursday 9:20 AM–10:50 AM', 'CG 2077', 'Angie Raymond', 7, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course studies commercial law, the law of debtors and creditors'' rights as it affects the decisions of business managers, accounting professionals, financial managers, and management consultants. The remainder of the course studies personal property and real property issues, including the law of the landlord/tenant, insurance, and trusts and estates. Property law issues considered include the law of bailments and liability of landlords for torts committed by third parties. It continues with a survey of the law of suretyship and the law of secured transactions.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-L 540', 'COMMERCIAL FINANCE LAW: CREDITORS'' RIGHT', '3266', 'Closed', 'TuTh Tuesday, Thursday 1:10 PM–2:40 PM', 'CG 2063', 'Angie Raymond', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course studies commercial law, the law of debtors and creditors'' rights as it affects the decisions of business managers, accounting professionals, financial managers, and management consultants. The remainder of the course studies personal property and real property issues, including the law of the landlord/tenant, insurance, and trusts and estates. Property law issues considered include the law of bailments and liability of landlords for torts committed by third parties. It continues with a survey of the law of suretyship and the law of secured transactions.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-L 541', 'CORPORATE FINANCE LAW AND BUSINESS PLANNING', '4270', 'Class Status', 'TuTh Tuesday, Thursday 9:20 AM–10:50 AM', 'CG 2061', 'Suneal Bedi', 7, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course studies the many forms of business, the law affecting the financing of business ventures, the liability of mangers of business enterprises, and the liability of professionals and consultants providing services to clients. The course begins with a student of business forms, especially corporations and limited liability companies, but also partnerships, limited partnerships and limited partnerships. Important topics include choosing a form of business appropriate to a business venture, financing business ventures, accommodating the interests of majority and minority owners of business ventures.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-L 541', 'CORPORATE FINANCE LAW AND BUSINESS PLANNING', '3267', 'Closed', 'TuTh Tuesday, Thursday 11:15 AM–12:45 PM', 'CG 1040', 'Suneal Bedi', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course studies the many forms of business, the law affecting the financing of business ventures, the liability of mangers of business enterprises, and the liability of professionals and consultants providing services to clients. The course begins with a student of business forms, especially corporations and limited liability companies, but also partnerships, limited partnerships and limited partnerships. Important topics include choosing a form of business appropriate to a business venture, financing business ventures, accommodating the interests of majority and minority owners of business ventures.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-M 295', 'MARKETING IN OUR WORLD TODAY', '12007', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'HH 1030', 'Paul Palmer', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course provides an introduction to the field of marketing as it functions in our world today. It includes discussion of key marketing decisions, including market segmentation, branding and brand differentiation, pricing, product management, promotion, channel selection and customer service. It also focuses on recent trends in marketing.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 300', 'INTRODUCTION TO MARKETING', '6137', 'Closed', NULL, 'MW Monday, Wednesday 5:30 PM–6:45 PM Regular Academic Session 8/25/2025–12/19/2025', 'BH 005', NULL, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examination of the market economy and marketing institutions in the U.S. Decision making and planning from the manager''s point of view; impact of marketing actions from the consumer''s point of view.', ARRAY['Class uses IU eTexts'], NULL),
