    ('BUS-M 303', 'MARKETING RESEARCH', '1197', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'HH 2047', 'Brian Vander Schee', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Focuses on the role of research in marketing decision making. Topics include defining research objectives, syndicated and secondary data sources of marketing information, exploratory research methods, survey research design, observational research techniques, experimental design, sampling procedures, data collection and analysis, and communicating research findings.', ARRAY[]::TEXT[], NULL),
