    ('BUS-M 306', 'GLOBAL SALES WORKSHOP I', '5583', 'Closed', 'Tu Tuesday 7:00 PM–9:00 PM', 'HH 4034', 'Charles Ragland', 0, NULL, 'Practicum', '1', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Global Sales Workshop I is an interactive and intensive education program designed for students with a strong desire to pursue a career in sales. The primary focus will be on advanced development of the skills necessary to be successful in a professional selling position.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 310', 'BRAND MANAGEMENT PRACTICUM', '31857', 'Closed', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'HH 2047', 'Nancy Paton', 0, NULL, 'Practicum', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course is a unique learning experience for students interested in brand management or working as a creative service provider for brand. You will be on a team with 4-5 classmates, along with a real national brand manager who gives you a "brand challenge" to work on for 10 weeks.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-M 310', 'BRAND MANAGEMENT PRACTICUM', '33608', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'CG 3044', 'Kelly King', 0, NULL, 'Practicum', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course is a unique learning experience for students interested in brand management or working as a creative service provider for brand. You will be on a team with 4-5 classmates, along with a real national brand manager who gives you a "brand challenge" to work on for 10 weeks.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-M 311', 'INTRODUCTION TO MARKETING COMMUNICATION', '4268', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'HH 1030', 'Ann Bastianelli', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course introduces non-marketing majors to the field of advertising and promotion. You will learn to understand how advertising, promotions, and other forms of marketing communications are developed and managed. Following this class, you should be able to comfortably discuss activities of those in advertising, public relations, and promotion management.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 311', 'INTRODUCTION TO MARKETING COMMUNICATION', '4269', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HH 1030', 'Ann Bastianelli', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course introduces non-marketing majors to the field of advertising and promotion. You will learn to understand how advertising, promotions, and other forms of marketing communications are developed and managed. Following this class, you should be able to comfortably discuss activities of those in advertising, public relations, and promotion management.', ARRAY[]::TEXT[], NULL),
