    ('BUS-M 312', 'RETAIL MARKETING MANAGEMENT', '6175', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 2055', 'Kristina Harrison', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course introduces non-marketing majors to the field of retail marketing management. You will learn to critically analyze the retailing process, the environment within which it operates, and the institutions and functions that are performed.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-M 312', 'RETAIL MARKETING MANAGEMENT', '29987', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 2055', 'Kristina Harrison', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course introduces non-marketing majors to the field of retail marketing management. You will learn to critically analyze the retailing process, the environment within which it operates, and the institutions and functions that are performed.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-M 330', 'CONSULTATIVE SELLING', '3097', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'CG 3044', 'Michelle Lane', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course is designed to provide insights into the sales profession by examining the role of persuasive communication and customer relationship management behaviors, principles, strategies, and actions. It will provide students an opportunity to plan, practice, and review those verbal behaviors associated with sales call success in order to persuade others to think differently regarding ideas, opinions, products, and services.', ARRAY[]::TEXT[], NULL),
