    ('BUS-M 330', 'CONSULTATIVE SELLING', '29986', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'HH 2055', 'Robert Peterson', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course is designed to provide insights into the sales profession by examining the role of persuasive communication and customer relationship management behaviors, principles, strategies, and actions. It will provide students an opportunity to plan, practice, and review those verbal behaviors associated with sales call success in order to persuade others to think differently regarding ideas, opinions, products, and services.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 339', 'RETAIL MARKETING ANALYTICS', '11394', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HH 2047', 'John Talbott', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course will use a text and an ecommerce simulation, case studies with data sets, and data from retailers as material for employing a variety of data analysis techniques in class. This analysis is focused on developing insights that allow retail managers to more effectively serve their customers.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 344', 'CREATIVITY AND COMMUNICATION', '3476', 'Closed', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'HH 2055', 'Kelly King', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Develops various creativity and communication skills necessary for marketing careers. Topics include models of and barriers to creativity, and cover various techniques for stimulating personal and professional creative skills. In addition, interpersonal, professional, visual design, and computer skills are developed. Sample assignments include producing various marketing materials, such as brochures, advertisements, and elaborate communication packages. In-class activities and examples stimulate interest through hands-on experience. Unique concluding activities require students to integrate skills acquired into one final project and/or presenation.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 344', 'CREATIVITY AND COMMUNICATION', '3478', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HH 2055', 'Kelly King', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Develops various creativity and communication skills necessary for marketing careers. Topics include models of and barriers to creativity, and cover various techniques for stimulating personal and professional creative skills. In addition, interpersonal, professional, visual design, and computer skills are developed. Sample assignments include producing various marketing materials, such as brochures, advertisements, and elaborate communication packages. In-class activities and examples stimulate interest through hands-on experience. Unique concluding activities require students to integrate skills acquired into one final project and/or presenation.', ARRAY[]::TEXT[], NULL),
