    ('BUS-M 349', 'RETAIL WORKSHOP', '8056', 'Closed', 'Tu Tuesday 3:55 PM–6:55 PM', 'HH 2047', 'Dana Olsen', 0, NULL, 'Practicum', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Designed to foster transference of knowledge into competencies required for successful entry into corporate retailing, solidify retail practice fundamentals, and gain exposure to retailing challenges and opportunities.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 355', 'TOPICS IN MARKETING', '32095', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 2047', 'Dennis Spahr', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Variable topic, variable credit course in Marketing.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 370', 'I-CORE - MARKETING COMPONENT', '1202', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:05 AM', 'HH 2083', 'Barbara Wooldridge', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'The marketing component covers marketing planning and decision making examined from the firm and consumer points of view. Topics include the marketing concept and its company-wide implications, the integration of marketing with other functions, and the role that product, price, promotion, and distribution play in marketing strategy and implementation. Includes a cross-functional case done in teams.', ARRAY['Class uses IU eTexts'], NULL),
