    ('BUS-M 370', 'I-CORE - MARKETING COMPONENT', '11928', 'Closed', 'MW Monday, Wednesday 3:45 PM–4:50 PM', 'HH 1055', 'Kristy McManus', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'The marketing component covers marketing planning and decision making examined from the firm and consumer points of view. Topics include the marketing concept and its company-wide implications, the integration of marketing with other functions, and the role that product, price, promotion, and distribution play in marketing strategy and implementation. Includes a cross-functional case done in teams.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-M 401', 'INTERNATIONAL MARKETING', '11081', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'HH 2055', 'Chad McBride', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Application of strategic marketing concepts and theory to the international arena. Stresses development of global perspective in understanding the uncontrollable forces affecting international operations and their impact upon the marketing mix. Examines the various marking functions within an international perspective.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-M 405', 'CONSUMER BEHAVIOR', '1205', 'Closed', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'HH 3075', 'Mansur Khamitov', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course provides a detailed understanding of how marketers create value for customers, what motivates shoppers to buy, how consumers process information and make decisions, persuasion techniques, cross-cultural influences on consumer behavior, and the impact of sustainable business practices on consumer choice.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-M 405', 'CONSUMER BEHAVIOR', '1206', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HH 3075', 'Mansur Khamitov', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course provides a detailed understanding of how marketers create value for customers, what motivates shoppers to buy, how consumers process information and make decisions, persuasion techniques, cross-cultural influences on consumer behavior, and the impact of sustainable business practices on consumer choice.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-M 405', 'CONSUMER BEHAVIOR', '10420', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HH 3075', 'Mansur Khamitov', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course provides a detailed understanding of how marketers create value for customers, what motivates shoppers to buy, how consumers process information and make decisions, persuasion techniques, cross-cultural influences on consumer behavior, and the impact of sustainable business practices on consumer choice.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-M 405', 'CONSUMER BEHAVIOR', '32230', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'HH 3075', 'Kristina Harrison', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course provides a detailed understanding of how marketers create value for customers, what motivates shoppers to buy, how consumers process information and make decisions, persuasion techniques, cross-cultural influences on consumer behavior, and the impact of sustainable business practices on consumer choice.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-M 405', 'CONSUMER BEHAVIOR', '32232', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'HH 3075', 'Kristina Harrison', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course provides a detailed understanding of how marketers create value for customers, what motivates shoppers to buy, how consumers process information and make decisions, persuasion techniques, cross-cultural influences on consumer behavior, and the impact of sustainable business practices on consumer choice.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-M 406', 'GLOBAL SALES WORKSHOP 2', '5584', 'Closed', 'Tu Tuesday 7:00 PM–9:00 PM', 'HH 4034', 'Charles Ragland', 0, NULL, 'Practicum', '0', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Global Sales Workshop II is an interactive and intensive education program designed for students with a strong desire to pursue a career in sales. The primary focus will be on advanced development of the skills necessary to be successful in a professional selling position. This course is a continuation of M306.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 407', 'BUSINESS-TO-BUSINESS MARKETING', '7058', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'HH 1030', 'James Threlkeld', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the unique techniques required to successfully market products and services to an organizational buyer rather than individual consumers or households. Organizational customers can include "for profit" businesses, governmental bodies and "not-for-profit" institutions. The major components of the course include: organizational buyer behavior, designing and managing profitable distribution channels, value based pricing, negotiation strategies, integrated marketing communication tactics and sales resource management.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 415', 'ADVERTISING AND INTEGRATED MARKETING COMMUNICATIONS', '11077', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'HH 1030', 'Ann Bastianelli', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Basic advertising and sales-promotion concepts. The design, management, and integration of a firm''s promotional strategy. Public policy aspects and the role oof advertising in marketing communications in different cultures.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 419', 'RETAIL STRATEGY', '1207', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'HH 3075', 'Dana Olsen', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'The course objective is to critically analyze the key marketing processes and strategic decisions made by major retail companies within the U.S. retailing industry. The course examines business challenges and opportunities related to driving and sustaining retailer''s shareholder value. Topics include financial requirements for publicly held retail firms, sustaining store-as-brand identity, developing and refining merchandising plans, pricing tactics, in-store execution, and customer''s experience management.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-M 419', 'RETAIL STRATEGY', '14258', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HH 3075', 'Dana Olsen', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'The course objective is to critically analyze the key marketing processes and strategic decisions made by major retail companies within the U.S. retailing industry. The course examines business challenges and opportunities related to driving and sustaining retailer''s shareholder value. Topics include financial requirements for publicly held retail firms, sustaining store-as-brand identity, developing and refining merchandising plans, pricing tactics, in-store execution, and customer''s experience management.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-M 426', 'SALES MANAGEMENT', '3089', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'HH 3075', 'Charles Ragland', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Students will engage in an interactive exploration of the strategic and tactical issues important to managing a professional sales organization. Key topics will include organizing a sales force, recruiting, training, compensation, motivation, forecasting, territory design, evaluation, and control. Lectures and case studies.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 426', 'SALES MANAGEMENT', '6926', 'Closed', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'HH 3075', 'Charles Ragland', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Students will engage in an interactive exploration of the strategic and tactical issues important to managing a professional sales organization. Key topics will include organizing a sales force, recruiting, training, compensation, motivation, forecasting, territory design, evaluation, and control. Lectures and case studies.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 428', 'CUSTOMER RELATIONSHIP MANAGEMENT AND DIGITAL ANALYTICS', '11082', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'HH 2047', 'Sarang Sunder', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Course is designed to meet the increasing demands from the industry and recruiters for the application of quantitative and analytical skills to support sophisticated marketing decision making. Content of this course is based on cutting-edge research in optimization and interactive marketing to study customer relationship management (CRM) and digital analytics.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 432', 'DIGITAL MARKETING', '9537', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'HH 3075', 'Kelley Wight', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Marketing in the digital age is markedly different than in the past. Students get a hands-on experience with critiquing and creating digital marketing strategies.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 432', 'DIGITAL MARKETING', '10592', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 3075', 'Kelley Wight', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Marketing in the digital age is markedly different than in the past. Students get a hands-on experience with critiquing and creating digital marketing strategies.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 432', 'DIGITAL MARKETING', '11395', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 3075', 'Kelley Wight', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Marketing in the digital age is markedly different than in the past. Students get a hands-on experience with critiquing and creating digital marketing strategies.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 436', 'ADVANCED PROFESSIONAL SALES PRACTICUM', '9024', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'CG 3044', 'Michelle Lane', 0, NULL, 'Practicum', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This is interactive and intensive education course designed for students pursuing a career in professional sales and marketing. The primary objective is to refine skills in the professional sales process.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 450', 'MARKETING STRATEGY', '1208', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'HH 3075', 'Matthew O Hern', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Focuses on marketing''s role in gaining a sustainable competitive advantage. Topics include competitor analysis, customer analysis, marketing environmental analysis, market potential analysis, and managing competitive interaction. Emphasis is on applications through the use of case studies and/or marketing game simulation of competitive interaction and the development of a strategic marketing plan.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 450', 'MARKETING STRATEGY', '11067', 'Closed', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'HH 3075', 'Matthew O Hern', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Focuses on marketing''s role in gaining a sustainable competitive advantage. Topics include competitor analysis, customer analysis, marketing environmental analysis, market potential analysis, and managing competitive interaction. Emphasis is on applications through the use of case studies and/or marketing game simulation of competitive interaction and the development of a strategic marketing plan.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 455', 'TOPICS IN MARKETING', '14794', 'Closed', 'Th Thursday 3:55 PM–6:25 PM', 'HH 2047', 'John Talbott', 0, NULL, 'Practicum', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Variable topic, variable credit course in Marketing.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 470', 'CONTENT MARKETING PRACTICUM', '31840', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'CG 3044', 'Jennifer Riley Simone', 0, NULL, 'Practicum', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course is focused on giving students business-world experience in creating a content marketing strategy and implementation plan, as well as the corresponding written and visual content. Students will be required to write blogs/whitepapers/social media captions etc. and design associated visuals, such as images and video for digital distribution.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 512', 'MARKETING STRATEGY', '1209', 'Class Status', 'MW Monday, Wednesday 11:15 AM–12:45 PM', 'CG 2077', 'Lopo Rego', 6, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course will develop your knowledge of key concepts related to improving the profitability of established lines of business, but through the use of case studies and analytical exercises, you will also see how to apply these concepts. Product line strategy will be discussed, which addresses the issue or market coverage and has a major effect on your market share.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 512', 'MARKETING STRATEGY', '14988', 'Class Status', 'MW Monday, Wednesday 1:10 PM–2:40 PM', 'CG 2077', 'Lopo Rego', 1, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course will develop your knowledge of key concepts related to improving the profitability of established lines of business, but through the use of case studies and analytical exercises, you will also see how to apply these concepts. Product line strategy will be discussed, which addresses the issue or market coverage and has a major effect on your market share.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 530', 'BUSINESS MARKETING STRATEGY AND MANAGEMENT', '1210', 'Closed', 'TuTh Tuesday, Thursday 11:15 AM–12:45 PM', 'CG 2063', 'Joshua Gildea', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course focuses on the process of marketing to organizations, including other businesses that use the product or service or incorporate the product into what they manufacture, not-for-profit institutions such as hospitals and universities, and government agencies. Topics covered include: managing ongoing customer relationships, business product strategy and management, reseller and distribution system.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 550', 'CONSUMER INSIGHTS', '12393', 'Class Status', 'MW Monday, Wednesday 1:10 PM–2:40 PM', 'CG 2063', 'Keith Niedermeier', 7, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Understanding customers is fundamental to the success of any organization. This course provides a structured approach to understanding customer responses in its many forms. The course emphasis will be on the hands-on use of information obtained from customers to craft marketing programs.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 550', 'CONSUMER INSIGHTS', '31838', 'Class Status', 'MW Monday, Wednesday 9:20 AM–10:50 AM', 'CG 2063', 'Keith Niedermeier', 1, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Understanding customers is fundamental to the success of any organization. This course provides a structured approach to understanding customer responses in its many forms. The course emphasis will be on the hands-on use of information obtained from customers to craft marketing programs.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 574', 'PRICING MANAGEMENT', '5243', 'Class Status', 'MW Monday, Wednesday 11:15 AM–12:45 PM', 'CG 2069', 'Koray Cosguner', 5, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course provides students with conceptual and analytical tools for making informed pricing decisions. Issues in buyer price sensitivity, how firms can improve their performance through different pricing approaches, and value-based pricing tools are discussed. Knowledge gained is applicable to pricing in both B2C and B2B contexts.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 574', 'PRICING MANAGEMENT', '31837', 'Class Status', 'MW Monday, Wednesday 9:20 AM–10:50 AM', 'CG 2063', 'Koray Cosguner', 4, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course provides students with conceptual and analytical tools for making informed pricing decisions. Issues in buyer price sensitivity, how firms can improve their performance through different pricing approaches, and value-based pricing tools are discussed. Knowledge gained is applicable to pricing in both B2C and B2B contexts.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 590', 'INDEPENDENT STUDY IN MARKETING', '37526', 'Closed', 'Kelley Second Seven Week', NULL, 'Joshua Gildea', 0, NULL, 'Independent Study', '1.5', NULL, ARRAY[]::TEXT[], 'For advanced MBA students engaged in special study projects.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 595', 'SPECIAL TOPICS IN MARKETING', '33628', 'Class Status', 'TuTh Tuesday, Thursday 9:20 AM–10:50 AM', 'CG 2069', 'Girish Mallapragada', 8, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Topics covered will vary with faculty and student interests. To provide an opportunity for the study of newly emerging topics in marketing management and research. Topics will be announced prior to registration.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 650', 'RESEARCH METHODS IN MARKETING', '29988', 'Class Status', NULL, NULL, 'Krista Li', 13, NULL, 'Lecture', '1.5', NULL, ARRAY[]::TEXT[], 'The general objective of this course is to provide a basic understanding of the research process and the tools needed to design and execute scientific research on behavioral and organizational issues in business. A major focus will be on understanding the basic principles of latent variable structural equation modeling.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 651', 'CONSUMER BEHAVIOR', '29990', 'Class Status', NULL, NULL, 'H. Krishnan', 14, NULL, 'Lecture', '1.5', NULL, ARRAY[]::TEXT[], 'The course purpose is to provide a strong foundation for critical thinking in the area of consumer behavior and decision making using concepts from cognitive and social psychology, behavioral theory and sociology. Students will develop skills allowing them to critically evaluate various perspectives, theories, and methodologies that form the field.', ARRAY[]::TEXT[], NULL),
    ('BUS-M 651', 'CONSUMER BEHAVIOR', '29991', 'Class Status', NULL, NULL, 'H. Krishnan', 14, NULL, 'Lecture', '1.5', NULL, ARRAY[]::TEXT[], 'The course purpose is to provide a strong foundation for critical thinking in the area of consumer behavior and decision making using concepts from cognitive and social psychology, behavioral theory and sociology. Students will develop skills allowing them to critically evaluate various perspectives, theories, and methodologies that form the field.', ARRAY[]::TEXT[], NULL),
    ('BUS-P 254', 'INTRODUCTION TO BUSINESS OPERATIONS CONSULTING', '15089', 'Closed', 'F Friday 9:35 AM–12:35 PM', 'HH 3034', 'Katie Votolato', 0, NULL, 'Practicum', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course engages students in discussions with business operations consulting practitioners so that they can understand and apply the frameworks, tools and techniques used in business operations consulting. The culmination of what is learned throughout the course will be a team case presentation that includes analysis of a real-world situation.', ARRAY[]::TEXT[], NULL),
    ('BUS-P 300', 'INTRODUCTION TO OPERATIONS MANAGEMENT', '1211', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'WB WEB', 'Greg Mejias', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides an overview of operating decisions and practices in both manufacturing- and service-oriented firms. While no attempt is made to cover any particular area in-depth, standard terms and concepts required to communicate effectively with operating personnel are introduced.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 300', 'INTRODUCTION TO OPERATIONS MANAGEMENT', '6845', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'WB WEB', 'Greg Mejias', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides an overview of operating decisions and practices in both manufacturing- and service-oriented firms. While no attempt is made to cover any particular area in-depth, standard terms and concepts required to communicate effectively with operating personnel are introduced.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 300', 'INTRODUCTION TO OPERATIONS MANAGEMENT', '8066', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'WB WEB', 'Greg Mejias', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides an overview of operating decisions and practices in both manufacturing- and service-oriented firms. While no attempt is made to cover any particular area in-depth, standard terms and concepts required to communicate effectively with operating personnel are introduced.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 304', 'HONORS OPERATIONS MANAGEMENT', '1212', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'HH 4000', 'RJ Niewoehner', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'A survey course concerned with the production and distribution of goods and services. It is a part of the integrative core, along with survey courses in finance and marketing. Topics include: inventory management, demand forecasting, aggregate production planning, shop scheduling, project management, quality control, and layout and process design. The primary focus for integration is a case problem at the end of the semester.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 304', 'HONORS OPERATIONS MANAGEMENT', '1213', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HH 4000', 'Finn Petersen', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'A survey course concerned with the production and distribution of goods and services. It is a part of the integrative core, along with survey courses in finance and marketing. Topics include: inventory management, demand forecasting, aggregate production planning, shop scheduling, project management, quality control, and layout and process design. The primary focus for integration is a case problem at the end of the semester.', ARRAY['Class uses IU eTexts'], NULL),
