    ('BUS-P 304', 'HONORS OPERATIONS MANAGEMENT', '11957', 'Closed', 'TuTh Tuesday, Thursday 9:45 AM–11:00 AM', 'HH 4026', 'RJ Niewoehner', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'A survey course concerned with the production and distribution of goods and services. It is a part of the integrative core, along with survey courses in finance and marketing. Topics include: inventory management, demand forecasting, aggregate production planning, shop scheduling, project management, quality control, and layout and process design. The primary focus for integration is a case problem at the end of the semester.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 304', 'HONORS OPERATIONS MANAGEMENT', '11958', 'Closed', 'TuTh Tuesday, Thursday 11:20 AM–12:35 PM', 'HH 4026', 'Finn Petersen', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'A survey course concerned with the production and distribution of goods and services. It is a part of the integrative core, along with survey courses in finance and marketing. Topics include: inventory management, demand forecasting, aggregate production planning, shop scheduling, project management, quality control, and layout and process design. The primary focus for integration is a case problem at the end of the semester.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 304', 'HONORS OPERATIONS MANAGEMENT', '11959', 'Closed', 'TuTh Tuesday, Thursday 3:45 PM–5:00 PM', 'HH 4026', 'Finn Petersen', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'A survey course concerned with the production and distribution of goods and services. It is a part of the integrative core, along with survey courses in finance and marketing. Topics include: inventory management, demand forecasting, aggregate production planning, shop scheduling, project management, quality control, and layout and process design. The primary focus for integration is a case problem at the end of the semester.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 319', 'SUPPLY CHAIN MANAGEMENT WITH DIGITAL TECHNOLOGIES', '9737', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 3079', 'Pam Manhart', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Supply chain management is an integrated approach to planning, implementing and controlling flow of information, materials and services from raw material to finished product for distribution to customers and includes topics such as facility network design, supply chain coordination, forecasting, omnichannel retail, inventory management, transportation network design, sourcing and sustainability.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 319', 'SUPPLY CHAIN MANAGEMENT WITH DIGITAL TECHNOLOGIES', '11486', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'HH 3000', 'Pam Manhart', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Supply chain management is an integrated approach to planning, implementing and controlling flow of information, materials and services from raw material to finished product for distribution to customers and includes topics such as facility network design, supply chain coordination, forecasting, omnichannel retail, inventory management, transportation network design, sourcing and sustainability.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 319', 'SUPPLY CHAIN MANAGEMENT WITH DIGITAL TECHNOLOGIES', '14658', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 3079', 'Pam Manhart', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Supply chain management is an integrated approach to planning, implementing and controlling flow of information, materials and services from raw material to finished product for distribution to customers and includes topics such as facility network design, supply chain coordination, forecasting, omnichannel retail, inventory management, transportation network design, sourcing and sustainability.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 320', 'SUPPLY CHAIN MANAGEMENT: GLOBAL SOURCING', '3081', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'HH 3079', 'Scott Dobos', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Sourcing is the process of acquiring goods and services to support an organization''s operations and includes topics such as 1) operational sourcing that identifies the purchase function and activities; 2) strategic sourcing that matches business with sourcing strategies; and 3) future of sourcing including Industry 4.0, blockchain with smart contracting.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 320', 'SUPPLY CHAIN MANAGEMENT: GLOBAL SOURCING', '4500', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HH 3079', 'Scott Dobos', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Sourcing is the process of acquiring goods and services to support an organization''s operations and includes topics such as 1) operational sourcing that identifies the purchase function and activities; 2) strategic sourcing that matches business with sourcing strategies; and 3) future of sourcing including Industry 4.0, blockchain with smart contracting.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 320', 'SUPPLY CHAIN MANAGEMENT: GLOBAL SOURCING', '31490', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HH 3079', 'Scott Dobos', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Sourcing is the process of acquiring goods and services to support an organization''s operations and includes topics such as 1) operational sourcing that identifies the purchase function and activities; 2) strategic sourcing that matches business with sourcing strategies; and 3) future of sourcing including Industry 4.0, blockchain with smart contracting.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 354', 'BUSINESS OPERATIONS CONSULTING: ESSENTIALS FOR SUCCESS', '15090', 'Closed', 'F Friday 9:35 AM–12:35 PM', 'HH 3046', 'Katie Votolato', 0, NULL, 'Practicum', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'The objective of this course is to prepare students for careers in business operations consulting. Our primary learning objectives are to better understand the lifecycle of a business operations consulting engagement, selling and proposing business operations consulting services, and the the ethical dilemmas one encounters in business operations consulting.', ARRAY[]::TEXT[], NULL),
    ('BUS-P 370', 'I-CORE - OPERATIONS COMPONENT', '1214', 'Closed', 'MW Monday, Wednesday 9:15 AM–10:20 AM', 'HH 2083', 'Russell Clark', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'The operations component is concerned with the production and distribution of goods and services. Topics include inventory management, demand forecasting, aggregate productions planning, shop scheduling, project management, quality control, and layout and process design. Includes a cross-functional case done in teams.', ARRAY['Class uses IU eTexts'], NULL),
