    ('BUS-P 370', 'I-CORE - OPERATIONS COMPONENT', '11932', 'Closed', 'TuTh Tuesday, Thursday 5:00 PM–6:05 PM', 'HH 1055', 'Syd Alavi', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'The operations component is concerned with the production and distribution of goods and services. Topics include inventory management, demand forecasting, aggregate productions planning, shop scheduling, project management, quality control, and layout and process design. Includes a cross-functional case done in teams.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 429', 'OPERATIONS PROCESSES', '1217', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HH 1038', 'Yuwei Zhou', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the analysis and design of the processes by which products or services are created and delivered to customers and includes topics such as bottleneck analysis, process design principles, static process analysis, value chain analysis and lean, process variability and quality, and queueing models.', ARRAY[]::TEXT[], NULL),
    ('BUS-P 429', 'OPERATIONS PROCESSES', '6974', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HH 1038', 'Yuwei Zhou', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the analysis and design of the processes by which products or services are created and delivered to customers and includes topics such as bottleneck analysis, process design principles, static process analysis, value chain analysis and lean, process variability and quality, and queueing models.', ARRAY[]::TEXT[], NULL),
    ('BUS-P 429', 'OPERATIONS PROCESSES', '29981', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'HH 1038', 'Yuwei Zhou', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the analysis and design of the processes by which products or services are created and delivered to customers and includes topics such as bottleneck analysis, process design principles, static process analysis, value chain analysis and lean, process variability and quality, and queueing models.', ARRAY[]::TEXT[], NULL),
    ('BUS-P 454', 'SUPPLY CHAIN CONSULTING PRACTICUM', '12449', 'Closed', 'TuTh Tuesday, Thursday 7:05 PM–8:20 PM', 'HH 3079', 'Scott Dobos', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Student teams work directly with corporate clients on solving actual business issues which begin with understanding the process and following a DMAIC foundation.', ARRAY[]::TEXT[], NULL),
    ('BUS-P 481', 'SUPPLY CHAIN PLANNING AND ANALYTICS', '6280', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'HH 4057', 'Rex Cutshall', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'At the intersection of supply chain management and data analytics, this course showcases quantitative approaches to modeling managerial tradeoffs and selecting among data-driven alternatives and includes topics such as static and adaptive forecasting, aggregate planning, sales and operations planning, deterministic and stochastic inventory models, optimal product availability, and revenue management.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 481', 'SUPPLY CHAIN PLANNING AND ANALYTICS', '7081', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'HH 4057', 'Rex Cutshall', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'At the intersection of supply chain management and data analytics, this course showcases quantitative approaches to modeling managerial tradeoffs and selecting among data-driven alternatives and includes topics such as static and adaptive forecasting, aggregate planning, sales and operations planning, deterministic and stochastic inventory models, optimal product availability, and revenue management.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-P 520', 'STRATEGIC SOURCING', '29900', 'Class Status', 'TuTh Tuesday, Thursday 9:20 AM–10:50 AM', 'CG 1026', 'Greg Mejias', 5, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Examines current and emerging best practices in sourcing activities that support and extend the strategic initiatives of the firm. Topics include global sourcing, specifications and standards; tools and techniques for strategic cost management; pricing practices; negotiation; quality; supplier evaluation, selection and development; sourcing performance metrics; and ethics.', ARRAY[]::TEXT[], NULL),
    ('BUS-P 579', 'EXPERIMENTAL COURSE IN SUPPLY CHAIN AND OPERATIONS', '34083', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'HH 3000', 'Pam Manhart', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This seven week course focuses upon a new topic in Supply Chain and Operations relevant to management decision making and appraisal of the external environment faced by organizations. Learning occurs through lecture, case discussion, problem solving, group projects, or completion of exercises that further the knowledge and skills of MBA students enrolled in the course.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-R 300', 'PRINCIPLES OF REAL ESTATE', '12450', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'GA 1106', 'Randy Lloyd', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-R 300', 'PRINCIPLES OF REAL ESTATE', '34200', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'HH 2057', 'Christopher Cockerham', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], NULL, ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-R 305', 'INTRODUCTION TO REAL ESTATE ANALYSIS', '3460', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'HH 1050', 'Doug McCoy', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Designed for students who may intend to take additional real estate courses. Topics include real estate law, brokerage, property management, appraising, mortgage finance, and investment analysis. Emphasis is placed on the analytical techniques applicable to real estate.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-R 305', 'INTRODUCTION TO REAL ESTATE ANALYSIS', '10340', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'HH 1050', 'Doug McCoy', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Designed for students who may intend to take additional real estate courses. Topics include real estate law, brokerage, property management, appraising, mortgage finance, and investment analysis. Emphasis is placed on the analytical techniques applicable to real estate.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-R 314', 'COMMERCIAL REAL ESTATE WORKSHOP I', '10406', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:55 PM', 'CG 1032', 'Christopher Cockerham', 0, NULL, 'Practicum', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course provides students with intense preparation for commercial real estate careers. The course develops skills relevant to the industry, and provides experential activity. The course emphasizes professional development skills for success and students are expected to attend industry networking sessions.', ARRAY[]::TEXT[], NULL),
    ('BUS-R 314', 'COMMERCIAL REAL ESTATE WORKSHOP I', '11384', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:55 PM', 'CG 2077', 'Dave Harstad', 0, NULL, 'Practicum', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course provides students with intense preparation for commercial real estate careers. The course develops skills relevant to the industry, and provides experential activity. The course emphasizes professional development skills for success and students are expected to attend industry networking sessions.', ARRAY[]::TEXT[], NULL),
    ('BUS-R 315', 'COMMERCIAL REAL ESTATE WORKSHOP II', '14019', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:55 PM', 'CG 2077', 'Dave Harstad', 0, NULL, 'Practicum', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course continues the intense preparation for commercial real estate careers. The course develops skills relevant to the industry, and provides experential activity. The course emphasizes professional development skills for success and students are expected to attend industry networking sessions.', ARRAY[]::TEXT[], NULL),
    ('BUS-R 315', 'COMMERCIAL REAL ESTATE WORKSHOP II', '14020', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:55 PM', 'CG 1032', 'Christopher Cockerham', 0, NULL, 'Practicum', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course continues the intense preparation for commercial real estate careers. The course develops skills relevant to the industry, and provides experential activity. The course emphasizes professional development skills for success and students are expected to attend industry networking sessions.', ARRAY[]::TEXT[], NULL),
    ('BUS-R 440', 'REAL ESTATE APPRAISALS', '1218', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'AC C112', 'Dave Harstad', 0, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'This course provides an understanding of the theory and techniques of income property valuation. It covers the material required by the Appraisal Foundation for general appraiser certification as well as material that is included in more advanced courses that prepare students for an appraisal designation.', ARRAY[]::TEXT[], NULL),
    ('BUS-R 440', 'REAL ESTATE APPRAISALS', '9055', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'IF 1104', 'Dave Harstad', 0, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'This course provides an understanding of the theory and techniques of income property valuation. It covers the material required by the Appraisal Foundation for general appraiser certification as well as material that is included in more advanced courses that prepare students for an appraisal designation.', ARRAY[]::TEXT[], NULL),
    ('BUS-R 443', 'REAL ESTATE FINANCE AND INVESTMENT ANALYSIS', '11270', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'HH 4006', 'Dave Harstad', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Case studies in effective techniques of real estate analysis by managers of business firms or real estate specialists. Selection, development, financing, and investment analysis of commercial, industrial, and residential real estate.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-R 448', 'REAL ESTATE PRIVATE EQUITY FUND', '12904', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'CG 2063', 'Thomas Peck', 0, NULL, 'Practicum', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'Commercial RE is a significant part of the U.S investment universe and gained prominence in recent years as an important component of most institutional investment portfolios. This class is a two-semester sequence of courses that deals primarily with how to analyze, select, manage investments in privately held commercial RE properties.', ARRAY[]::TEXT[], NULL),
    ('BUS-R 510', 'REAL ESTATE INVESTMENT ANALYSIS', '1219', 'Closed', 'MW Monday, Wednesday 9:20 AM–10:50 AM', 'CG 2061', 'Jun Zhu', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'An analysis of real estate investment from an equity investor''s point of view. Topics discussed include techniques used to analyze the expected cash flow from real estate income properties; the way that ownership forms and tax considerations affect those cash flows and rate of return; how factors such as the structure of ownership form, and tax considerations affect the riskiness of real estate income property; variety of different measures of risk; real estate appraisal is introduced with emphasis on the difficulties associated with estimating the value of real estate income property because of characteristics of the real estate market (versus the market for stocks and bonds); issues of leverage, ownership forms, and analysis for development projects are also covered.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-S 302', 'DIGITAL BUSINESS TECHNOLOGIES', '6476', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'CG 3075', 'Frank Akaiwa', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course focuses on the digital ecosystem, the interplay between physical and digital worlds, to explore digital trends and innovations for businesses. Course topics include enterprise modeling frameworks, enterprise system platforms, digital transformation, and the Software Development Lifecycle (SDLC) project management framework.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-S 302', 'DIGITAL BUSINESS TECHNOLOGIES', '6543', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 4055', 'Frank Akaiwa', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course focuses on the digital ecosystem, the interplay between physical and digital worlds, to explore digital trends and innovations for businesses. Course topics include enterprise modeling frameworks, enterprise system platforms, digital transformation, and the Software Development Lifecycle (SDLC) project management framework.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-S 302', 'DIGITAL BUSINESS TECHNOLOGIES', '6687', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'CG 3075', 'Frank Akaiwa', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course focuses on the digital ecosystem, the interplay between physical and digital worlds, to explore digital trends and innovations for businesses. Course topics include enterprise modeling frameworks, enterprise system platforms, digital transformation, and the Software Development Lifecycle (SDLC) project management framework.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-S 302', 'DIGITAL BUSINESS TECHNOLOGIES', '6980', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 4055', 'Frank Akaiwa', 0, NULL, 'Lecture', '3', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This course focuses on the digital ecosystem, the interplay between physical and digital worlds, to explore digital trends and innovations for businesses. Course topics include enterprise modeling frameworks, enterprise system platforms, digital transformation, and the Software Development Lifecycle (SDLC) project management framework.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-S 305', 'TECHNOLOGY INFRASTRUCTURE', '1220', 'Closed', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'HH 3079', 'Andrew Chickedantz', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course examines how computer networks move messages from one computer to another, and how firms design and deploy network infrastructure and includes topics such as five network layers, network technologies such as LAN and backbone network components, WAN technologies, network design, and network security and management.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-S 305', 'TECHNOLOGY INFRASTRUCTURE', '4488', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'HH 3079', 'Michael Clark', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course examines how computer networks move messages from one computer to another, and how firms design and deploy network infrastructure and includes topics such as five network layers, network technologies such as LAN and backbone network components, WAN technologies, network design, and network security and management.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-S 305', 'TECHNOLOGY INFRASTRUCTURE', '8914', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HH 3079', 'Alan Dennis', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course examines how computer networks move messages from one computer to another, and how firms design and deploy network infrastructure and includes topics such as five network layers, network technologies such as LAN and backbone network components, WAN technologies, network design, and network security and management.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-S 305', 'TECHNOLOGY INFRASTRUCTURE', '29982', 'Closed', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'HH 3079', 'Patrick Phillips', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course examines how computer networks move messages from one computer to another, and how firms design and deploy network infrastructure and includes topics such as five network layers, network technologies such as LAN and backbone network components, WAN technologies, network design, and network security and management.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-S 307', 'DATA DESIGN & MANAGEMENT', '3190', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 4079', 'Aaron Perry', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the lifecycle of data management including data requirements elicitation, conceptual and logical design along with database implementation/querying using SQL and NoSQL. Using hands-on tools, students learn how to apply key concepts of database design and write SQL/NoSQL queries to develop dashboards that dove-tail with business needs.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-S 307', 'DATA DESIGN & MANAGEMENT', '5868', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 4079', 'Aaron Perry', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the lifecycle of data management including data requirements elicitation, conceptual and logical design along with database implementation/querying using SQL and NoSQL. Using hands-on tools, students learn how to apply key concepts of database design and write SQL/NoSQL queries to develop dashboards that dove-tail with business needs.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-S 307', 'DATA DESIGN & MANAGEMENT', '6927', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'HH 4055', 'Jay Newquist', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the lifecycle of data management including data requirements elicitation, conceptual and logical design along with database implementation/querying using SQL and NoSQL. Using hands-on tools, students learn how to apply key concepts of database design and write SQL/NoSQL queries to develop dashboards that dove-tail with business needs.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-S 307', 'DATA DESIGN & MANAGEMENT', '6928', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'HH 4055', 'Jay Newquist', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the lifecycle of data management including data requirements elicitation, conceptual and logical design along with database implementation/querying using SQL and NoSQL. Using hands-on tools, students learn how to apply key concepts of database design and write SQL/NoSQL queries to develop dashboards that dove-tail with business needs.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-S 310', 'ANALYSIS AND DESIGN OF DIGITAL SOLUTIONS', '1221', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'HH 4057', 'Tony Emmons', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the development of the prototype of a digital solution for a business case, following an Agile approach and includes topics such as Scrum, Unified Modeling Language (UML), web development languages and tools such as HTML, CSS, and Bootstrap, which is used to create a responsive system.', ARRAY[]::TEXT[], NULL),
    ('BUS-S 310', 'ANALYSIS AND DESIGN OF DIGITAL SOLUTIONS', '6240', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'HH 4057', 'Tony Emmons', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the development of the prototype of a digital solution for a business case, following an Agile approach and includes topics such as Scrum, Unified Modeling Language (UML), web development languages and tools such as HTML, CSS, and Bootstrap, which is used to create a responsive system.', ARRAY[]::TEXT[], NULL),
    ('BUS-S 310', 'ANALYSIS AND DESIGN OF DIGITAL SOLUTIONS', '7826', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 4057', 'Tony Emmons', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on the development of the prototype of a digital solution for a business case, following an Agile approach and includes topics such as Scrum, Unified Modeling Language (UML), web development languages and tools such as HTML, CSS, and Bootstrap, which is used to create a responsive system.', ARRAY[]::TEXT[], NULL),
    ('BUS-S 326', 'WEB AND SOCIAL MEDIA ANALYTICS', '7916', 'Closed', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'HH 4057', 'Nick Brown', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on retrieving, visualizing, and analyzing social media and web traffic data to monitor and improve digital service performance. The course starts with technical understanding and practical applications of social network analysis. Next, it delves into managerial understanding and hands-on practice of web analytics for web performance optimization.', ARRAY[]::TEXT[], NULL),
    ('BUS-S 326', 'WEB AND SOCIAL MEDIA ANALYTICS', '9551', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'HH 4057', 'Nick Brown', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course focuses on retrieving, visualizing, and analyzing social media and web traffic data to monitor and improve digital service performance. The course starts with technical understanding and practical applications of social network analysis. Next, it delves into managerial understanding and hands-on practice of web analytics for web performance optimization.', ARRAY[]::TEXT[], NULL),
    ('BUS-S 355', 'TOPICS IN INFORMATION SYSTEMS', '10395', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HH 4079', 'Alfred Brendel', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Variable topic, variable credit course in Information Systems.', ARRAY[]::TEXT[], NULL),
    ('BUS-S 355', 'TOPICS IN INFORMATION SYSTEMS', '29899', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'HH 4079', 'Alfred Brendel', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Variable topic, variable credit course in Information Systems.', ARRAY[]::TEXT[], NULL),
    ('BUS-S 364', 'BUSINESS DATA PROGRAMMING', '9554', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HH 4079', 'Ankit Shah', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course employs business data programming to introduce the principles of programming for business analytics and includes topics such as data structures, loops, functions, file input/output, reading from data sources, and the use of Python packages such as NumPy, Pandas, Matplotlib, Seaborn to conduct the entire lifecycle of business analytics.', ARRAY[]::TEXT[], NULL),
