    ('BUS-W 212', 'EXPLORE ENTREPRENEURSHIP', '4265', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'HH 2057', 'Sara Cochran', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course is designed to expose you to the basic concepts and language of contemporary entrepreneurship. A primary objective of this course is to encourage entrepreneurial thinking and enable you to evaluate your personal prospects for entrepreneurship.', ARRAY['Class uses IU eTexts'], NULL),
