    ('BUS-W 212', 'EXPLORE ENTREPRENEURSHIP', '29834', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'HH 2057', 'Nick Mmbaga', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course is designed to expose you to the basic concepts and language of contemporary entrepreneurship. A primary objective of this course is to encourage entrepreneurial thinking and enable you to evaluate your personal prospects for entrepreneurship.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-W 212', 'EXPLORE ENTREPRENEURSHIP', '29835', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 2000', 'Sara Cochran', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This course is designed to expose you to the basic concepts and language of contemporary entrepreneurship. A primary objective of this course is to encourage entrepreneurial thinking and enable you to evaluate your personal prospects for entrepreneurship.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-W 235', 'IDEA VALIDATION & BUSINESS MODEL DEVELOPMENT', '10322', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'HH 3057', 'Rainie Tian', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'In this class, students work through a series of engagement exercises in order to mimic the pre-launch activities of a growth oriented startup. This class shows you how to thoughtfully take your idea from business concept through initial launch, and culminates with the development of crowdfunding pitch.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-W 235', 'IDEA VALIDATION & BUSINESS MODEL DEVELOPMENT', '11640', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HH 3057', 'Rainie Tian', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'In this class, students work through a series of engagement exercises in order to mimic the pre-launch activities of a growth oriented startup. This class shows you how to thoughtfully take your idea from business concept through initial launch, and culminates with the development of crowdfunding pitch.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-W 235', 'IDEA VALIDATION & BUSINESS MODEL DEVELOPMENT', '12687', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'HH 3057', 'Rainie Tian', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'In this class, students work through a series of engagement exercises in order to mimic the pre-launch activities of a growth oriented startup. This class shows you how to thoughtfully take your idea from business concept through initial launch, and culminates with the development of crowdfunding pitch.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-W 265', 'EXPLORING THE ENTREPRENEURIAL ECOSYSTEM', '12462', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HH 3057', 'Susan Batchelder', 0, NULL, 'Practicum', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This is the first of two consecutive courses in the workshop which build on the theory and application of entrepreneurial topics presented in the entrepreneurship and corporate innovation major. The focus of the course is on career education, networking, and skill development to help prepare students for an entrepreneurial career.', ARRAY[]::TEXT[], NULL),
    ('BUS-W 300', 'NEW VENTURE MANAGEMENT', '5621', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'WB WEB', 'Marty Pieratt', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Course provides an introduction to the world of smalll business ventures and entrepreneurship. The fundamentals of sound and effective management as these relate specifically to small businesspeople will be covered.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-W 300', 'NEW VENTURE MANAGEMENT', '14640', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'WB WEB', 'Marty Pieratt', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Course provides an introduction to the world of smalll business ventures and entrepreneurship. The fundamentals of sound and effective management as these relate specifically to small businesspeople will be covered.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-W 300', 'NEW VENTURE MANAGEMENT', '29836', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'WB WEB', 'Marty Pieratt', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Course provides an introduction to the world of smalll business ventures and entrepreneurship. The fundamentals of sound and effective management as these relate specifically to small businesspeople will be covered.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-W 313', 'NEW VENTURE PLANNING', '11530', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'HH 4006', 'Cy Megnin', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'Great ideas & inventions don''t necessarily make great companies. You have to HAVE A PLAN - whether it''s a complete business plan in a traditional format (if you''re seeking venture or bank financing), or at the very least, a plan for cash flow, product development and how to sell your service/product/concept.', ARRAY[]::TEXT[], NULL),
    ('BUS-W 365', 'ENGAGING WITH THE ENTREPRENEURIAL ECOSYSTEM', '29872', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'HH 3057', 'Susan Batchelder', 0, NULL, 'Practicum', '1.5', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'This is the second of two consecutive courses in the workshop which build on the theory and application of entrepreneurial topics presented in the entrepreneurship and corporate innovation major. The focus of the course is on career education, networking, and skill development to help prepare students for an entrepreneurial career.', ARRAY[]::TEXT[], NULL),
    ('BUS-W 420', 'CORPORATE VENTURING', '4476', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'HH 2049', 'Susan Batchelder', 0, NULL, 'Lecture', '3', 'HODGE HALL (BUSINESS SCHOOL)', ARRAY[]::TEXT[], 'The goal of this course is to learn about the entrepreneurial challenges faced by established firms. We will evaluate a range of issues from the perspective of a firm''s leaders and managers as they pertain to fostering entrepreneurship and launching new ventures.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-W 430', 'ORGANIZATIONS AND ORGANIZATIONAL DESIGN', '14810', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'AC C118', 'Damian Zivic', 0, NULL, 'Lecture', '3', 'CEDAR HALL', ARRAY[]::TEXT[], 'The objective of this class is to introduce the principles of organization design - the blueprint by which different parts of the organization (e.g., production, marketing, financial, accounting, and MIS systems) fit together to create an effective organization. Organization design provides the means by which strategy and goals are implemented so it is as important to a firm''s overall performance as financial performance, operational efficiencies or market share.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-W 499', 'COOP-INTERN WORK ASSIGN(OFF-CA)', '1223', 'Closed', NULL, NULL, 'Bridget Stomberg', 0, NULL, 'Internship', '0', NULL, ARRAY[]::TEXT[], 'A full-time work experience related to the student''s occupational interest. In most cases the student is off-campus for a one-semester work experience.', ARRAY[]::TEXT[], NULL),
    ('BUS-W 504', 'NEW VENTURE BUSINESS PLANNING', '34470', 'Class Status', 'TuTh Tuesday, Thursday 9:20 AM–10:50 AM', 'CG 1022', 'Susan Batchelder', 11, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'An in-depth descriptive effort on the part of the student to develop a business plan for a new venture that the student wishes to investigate. The business plan is the basic document of entrepreneurship. It communicates to many audiences: customers, suppliers, future employees and managers, and of course investors and lenders. We adopt a resource based framework for sustainable competitive advantage and encourage the students to examine the attributes of the resources controlled and controllable for their venture.', ARRAY[]::TEXT[], NULL),
    ('BUS-W 505', 'POWER, PERSUASION, INFLUENCE, NEGOTIATION', '13113', 'Class Status', 'MW Monday, Wednesday 1:10 PM–2:40 PM', 'CG 2077', 'Tatiana Kolovou', 4, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'The effective use of power, influence, and control in the modern organization. Designed to provide a broad overview of tactics and strategies currently in use. Some of the material is potentially offensive, manipulative, perhaps altogether unethical. It may at times seem to capitalize on individual vulnerability. Hopefully, these will not become tactics of choice for your use. Familiarity and sensitivity to such material may provide some awareness and insulation as you may more recognize abuses of power and influence in the future.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-W 505', 'POWER, PERSUASION, INFLUENCE, NEGOTIATION', '11819', 'Closed', 'MW Monday, Wednesday 11:15 AM–12:45 PM', 'CG 1022', 'Tatiana Kolovou', 0, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'The effective use of power, influence, and control in the modern organization. Designed to provide a broad overview of tactics and strategies currently in use. Some of the material is potentially offensive, manipulative, perhaps altogether unethical. It may at times seem to capitalize on individual vulnerability. Hopefully, these will not become tactics of choice for your use. Familiarity and sensitivity to such material may provide some awareness and insulation as you may more recognize abuses of power and influence in the future.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-W 506', 'ENTREPRENEURSHIP: LEADERSHIP AND PRACTICE', '34506', 'Class Status', 'TuTh Tuesday, Thursday 9:20 AM–10:50 AM', 'CG 1026', 'Susan Batchelder', 14, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'The purpose of this course is to introduce students to the general theories, principles, concepts, and practices of entrepreneurship. Concentrating in the development of an "entrepreneurial perspective" this course attempts to prepare MBA students to avoid or (at least) realize the pitfalls of new venture initiation, whether outside or inside of an organization.', ARRAY['Class uses IU eTexts'], NULL),
    ('BUS-W 561', 'MASTER OF SCIENCE IN MANAGEMENT PRACTICUM 1', '14941', 'Class Status', 'MW Monday, Wednesday 9:20 AM–10:50 AM', 'CG 2077', 'Rainie Tian', 15, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'This intense experiential course is designed to put you on the front lines of managerial problem-solving during which you will interact with a variety of professionals to gain exposure to different types of managerial jobs and industries.', ARRAY[]::TEXT[], NULL),
    ('BUS-W 574', 'CORPORATE ENTREPRENEURSHIP & INNOVATION', '10530', 'Class Status', 'MW Monday, Wednesday 1:10 PM–2:40 PM', 'CG 1022', 'Donald Kuratko', 13, NULL, 'Lecture', '1.5', 'GODFREY GRAD&EXEC ED CTR', ARRAY[]::TEXT[], 'The Corporate Entrepreneurship course is designed with two purposes in mind. First, the course explores practices and challenges involved when established companies initiate major business domain or model innovations. Second, the course reviews how companies can rely on strategic innovation to reinvigorate and renew themselves, their markets, or their industries.', ARRAY['Class uses IU eTexts'], NULL)
